import{_ as t,o as a,c as i,ag as r}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Pitching Analytics","description":"","frontmatter":{},"headers":[],"relativePath":"analytics/pitching.md","filePath":"analytics/pitching.md"}'),n={name:"analytics/pitching.md"};function o(l,e,c,s,h,d){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="pitching-analytics" tabindex="-1">Pitching Analytics <a class="header-anchor" href="#pitching-analytics" aria-label="Permalink to &quot;Pitching Analytics&quot;">​</a></h1><h2 id="pitch-heat-map" tabindex="-1">Pitch Heat Map <a class="header-anchor" href="#pitch-heat-map" aria-label="Permalink to &quot;Pitch Heat Map&quot;">​</a></h2><p>The heat map shows pitch location frequency across the strike zone and surrounding areas. Darker colors indicate more pitches thrown to that zone.</p><p>Use the heat map to identify:</p><ul><li>A pitcher&#39;s tendency to work inside or outside</li><li>Whether a pitcher challenges the zone or pitches around hitters</li><li>Command patterns — does the pitcher consistently hit their spots?</li></ul><h2 id="pitch-type-filter" tabindex="-1">Pitch Type Filter <a class="header-anchor" href="#pitch-type-filter" aria-label="Permalink to &quot;Pitch Type Filter&quot;">​</a></h2><p>Filter the heat map and all pitching analytics by pitch type to analyze command for each pitch separately. A pitcher may have excellent fastball command but inconsistent breaking ball location.</p><h2 id="velocity-trend" tabindex="-1">Velocity Trend <a class="header-anchor" href="#velocity-trend" aria-label="Permalink to &quot;Velocity Trend&quot;">​</a></h2><p>The velocity trend chart shows pitch speed over time with separate lines for each pitch type. Use this to:</p><ul><li>Monitor pitcher fatigue within a game (declining velocity)</li><li>Track velocity development over a season</li><li>Identify velocity differences between pitch types</li></ul><h2 id="strike-rate" tabindex="-1">Strike Rate <a class="header-anchor" href="#strike-rate" aria-label="Permalink to &quot;Strike Rate&quot;">​</a></h2><p>Strike percentage is displayed as a stat card. The threshold for concern is:</p><ul><li>Below 58% — command needs attention</li><li>Below 50% — significant command issue</li></ul><h2 id="era" tabindex="-1">ERA <a class="header-anchor" href="#era" aria-label="Permalink to &quot;ERA&quot;">​</a></h2><p>ERA is calculated using age-appropriate innings denominators based on your team level. See <a href="/analytics/era-explained.html">Understanding ERA</a> for details.</p><h2 id="strikeout-and-walk-rates" tabindex="-1">Strikeout and Walk Rates <a class="header-anchor" href="#strikeout-and-walk-rates" aria-label="Permalink to &quot;Strikeout and Walk Rates&quot;">​</a></h2><p>K/BB ratio is a key pitching performance indicator. A ratio above 2.0 is generally considered good at the youth level.</p>',17)])])}const m=t(n,[["render",o]]);export{u as __pageData,m as default};
